const amqp = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.QUEUE_NAME || 'payment_events';
const PREFETCH = Number(process.env.PREFETCH || 10);

async function processPayment(event) {
  const {
    paymentId,
    userId,
    amount,
    currency,
    method,
    action,
    metadata = {}
  } = event;

  console.log('Processing payment event:', {
    paymentId,
    userId,
    amount,
    currency,
    method,
    action
  });

  switch (action) {
    case 'charge':
      await chargePayment({ paymentId, userId, amount, currency, method, metadata });
      break;
    case 'refund':
      await refundPayment({ paymentId, userId, amount, currency, method, metadata });
      break;
    case 'capture':
      await capturePayment({ paymentId, userId, amount, currency, method, metadata });
      break;
    default:
      throw new Error(`Unsupported payment action: ${action}`);
  }
}

async function chargePayment(payment) {
  console.log(`Charging ${payment.amount} ${payment.currency} for user ${payment.userId} via ${payment.method}`);
  await simulateAsyncWork();
}

async function refundPayment(payment) {
  console.log(`Refunding ${payment.amount} ${payment.currency} for user ${payment.userId} via ${payment.method}`);
  await simulateAsyncWork();
}

async function capturePayment(payment) {
  console.log(`Capturing ${payment.amount} ${payment.currency} for user ${payment.userId} via ${payment.method}`);
  await simulateAsyncWork();
}

function simulateAsyncWork() {
  return new Promise(resolve => setTimeout(resolve, 300));
}

async function startConsumer() {
  const connection = await amqp.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  await channel.assertQueue(QUEUE_NAME, { durable: true });
  await channel.prefetch(PREFETCH);

  console.log(`Waiting for payment events on queue "${QUEUE_NAME}"`);

  channel.consume(
    QUEUE_NAME,
    async msg => {
      if (!msg) return;

      try {
        const content = msg.content.toString('utf8');
        const event = JSON.parse(content);

        await processPayment(event);

        channel.ack(msg);
      } catch (error) {
        console.error('Failed to process payment event:', error);
        channel.nack(msg, false, false);
      }
    },
    { noAck: false }
  );

  const shutdown = async signal => {
    console.log(`Received ${signal}, shutting down...`);
    try {
      await channel.close();
      await connection.close();
    } finally {
      process.exit(0);
    }
  };

  process.on('SIGINT', () => shutdown('SIGINT'));
  process.on('SIGTERM', () => shutdown('SIGTERM'));
}

startConsumer().catch(error => {
  console.error('Consumer startup failed:', error);
  process.exit(1);
});